INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-0563', 'A Marbella, superbes villas 5 chambres, très modernes, avec vues sur mer et sur golf.', 'Moderne, stijlvolle 5 slaapkamer villa op plan met zee en golf zichten in Marbella', 'Modern, stylish 5 bedroom off-plan villas with sea and golf views, in Marbella', 'Petite communauté de 14 villas exclusives avec 5 chambres, située à La Alqueria, un quartier résidentiel calme. La résidence bénéficie de vues panoramiques de presque 360° sur le terrain de golf, la montagne, et bien sûr sur la côté Méditerranéenne de Marbella jusqu''à Estepona. Les villas, spacieuses, élégantes et très lumineuses, sont construites dans un style architectural moderne. Les pièces et les terrasses sont conçues pour profiter au maximum de la vue qui entoure votre propriété. Espace supplémentaire disponible pour créer un spa, un home cinéma ou une salle de fitness. Garages privés, jardins paysagers, grandes terrasses et piscine complètent ces magnifiques villas. Également inclus: chauffage au sol, climatisation, système fonctionnant à l''énergie solaire, piscine individuelle d''eau salée, jardins avec arrosage automatique et éclairage ambiant, cheminée avec poêle au gaz. Prix: àpd 1.950.000 ? hors frais', 'Deze exclusieve residentie bestaande uit 14 5- slaapkamer villas is gelegen in La Aquería, een rustige omgeving met bijna 360 graden panoramisch zicht over golf terreinen, bergachtig landschap en natuurlijk de Mediterraanse kust van Marbella tot Estepona. Gebouwd in een modern architecturale stijl met een open plan lay-out is dit een zeer ruime woning die baadt in het natuurlijk zonlicht. De kamers en terrassen werden zo gebouwd zodat u ten volle kan genieten van het impresionante uitzicht, waar creatief desing hand in hand gaat met de beste materialen en nieuwste technologieën. Er is keuze uit 3 hoofdontwerpen en 3 onderverdelingen hierin. Daarnast kan u keuken, badkamers en afwerking verder personaliseren en bijvoorbeeld een spa, cinema, entertainment kamer of fitnesskamer installeren, Private garages, aangelegde tuinen ,ruime terrassen en ligplaats aan het zwembad maken deze prachtige woning af. Daarenboven heeft u vleorverwarming, airconditioning, zonnepanelen, zoutwater zwembad en tuinen met een automatisch sproeisysteem en een gas open haard. Prijs vanaf: ? 1 950 000 excl kosten', 'This select community of 14 five-bedroom villas that makes up the development is located in La Alquería, a quiet residential area. The development enjoys an almost 360-degree panoramaic view of golf courses, open mountain scenery and, of course, the Mediterranean coastline from Marbella towards Estepona. Built in a modern architectural style, with open-plan layouts that allow for flexible, appealing interior living spaces. Spacious, stylish and rich in natural light, the rooms and terraces are designed to make the most of the stunning views that surround your property, with creative design meeting the finest materials, construction standards and the latest technology to create luxurious modern homes for the 21st century. A choice of three main designs and three sub-designs is available to complement, along with personalised kitchen, bathroom and overall decorative fittings, with additional space available to create a spa, home cinema, entertainment area or gym. Private garages, landscaped gardens and spacious terraced areas and pool decks complete these magnificent villas. Also included are under floor heating, air conditioning system, solar power energy systems, individual salt water swimming pool, landscaped, manicured gardens complete with automatic irrigation and ambient lighting, and gas powered feature fireplaces. Prices start at 1.950.000 ? plus costs.', 1950000, 'a-marbella-superbes-villas-5-chambres-tres-modernes-avec-vues-sur-mer-et-sur-golf', 'moderne-stijlvolle-5-slaapkamer-villa-op-plan-met-zee-en-golf-zichten-in-marbella', 'modern-stylish-5-bedroom-off-plan-villas-with-sea-and-golf-views-in-marbella', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-0665', 'DERNIERES UNITES! Appartements 2 chambres exclusifs, situés dans de beaux jardins subtropicaux avec lagon privé', 'LAST UNITS! 2 slaapkamer appartementen gelegen in prachtige subtropische tuinen met privéstrand', 'Exclusive 2 bedroom apartments, with a private crystal lagoon,set in extensive subtropical gardens,at greatly discounted prices', 'Cette résidence s''étend à travers 40.000 m² de jardins exotiques et est située à côté d''un immense lagon privé aux eaux cristallines: un paradis naturel pour la pratique de nombreux sports nautiques tels que paddle surf, canoë, voile, kite surf, planche à voile... Construit dans un style méditerranéen contemporain, à Casares, une zone privilégiée de la Costa del Sol, à proximité de 3 terrains de golf et à courte distance en voiture des commerces et de la plage. La 1ère partie du développement offre des appartements 2 et 3 chambres et des lofts avec des terrasses spectaculaires. Les appartements, très lumineux, disposent d''une cuisine entièrement équipée, de la climatisation, d''un garage et d''une cave. Sécurité 24h/24. Prix: à partir de 555.000 ? hors frais.', 'Dit complex strekt zich uit over 40.000 m² exotische tuinen en is gelegen naast een grote privé-lagune met kristalhelder water: een natuurlijk paradijs voor het beoefenen van watersporten zoals paddle surfen, kanoën, zeilen, kitesurfen, zeilen ... Gebouwd in een moderne mediterrane stijl, in Casares, een bevoorrechte omgeving van de Costa del Sol. Dicht bij de 3 golfbanen en slechts een korte rit van de winkels en het strand. Het eerste deel van de ontwikkeling biedt appartementen met 2 en 3 slaapkamers en penthouses met spectaculaire terrassen. De appartementen met veel lichtinval hebben een volledig uitgeruste keuken, airconditioning, een garage, een kelder en 24u / 24 beveiliging. Prijs: ? 555.000 exclusief kosten.', 'This exclusive residential development stretches through over 40,000 m2 of exotic gardens. A development of buildings with a catching design of white lines and gentle outlines for its south-facing dwellings. Set next to a huge private crystal water lagoon, a natural paradise for numerous water sports, such as paddle surfing, canoeing, sailing, kite surfing and windsurfing, etc? The complex is built in contemporary Mediterranean style in Casares, a privileged zone on the Costa del Sol. Next to 3 golf courses and set in a tranquil countryside setting. The first phase of the development offers 2 and 3 bedroom apartments and lofts with spectacular terraces. The apartments come with fully fitted kitchens ,airconditioning, 24 hour security, garage and storage room. Large, open spaces and fully exterior rooms give all the apartments all the luminosity of the Mediterranean sun. The development is located a short drive from shops and the beach. Prices start at 285.000 ? excl. costs.', 555000, 'dernieres-unites-appartements-2-chambres-exclusifs-situes-dans-de-beaux-jardins-subtropicaux-avec-lagon-prive', 'last-units-2-slaapkamer-appartementen-gelegen-in-prachtige-subtropische-tuinen-met-privestrand', 'exclusive-2-bedroom-apartments-with-a-private-crystal-lagoon-set-in-extensive-subtropical-gardens-at-greatly-discounted-prices', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1361', 'Aguilas: superbes appartements en deux chambres', 'Aguilas : prachtige appartementen met twee kamers', '', 'Ce nouveau projet se situe sur les renforts de la montagne, offrant ainsi des vues extraordinaires sur la mer. Il se situe à 5 minutes du centre d''Aguilas, de ses commerces, bars et restaurants. La résidence propose deux belles grandes piscines, une aire de jeux pour les enfants, une zone chill out et enfin un jardin commun. Tous les appartements jouissent d''une place de parking en sous-sol avec la pré-installation pour une borne de recharge électrique. Les appartements se composent de deux chambres, de deux salles de bains et d''une grande pièce de vie regroupant cuisine ouverte, salon et salle à manger. Vous profiterez aussi de belles grandes terrasses. Les cuisines sont livrées avec four, four micro-ondes, plaque de cuisson et hotte. La climatisation est aussi comprise dans le prix. Prix à partir de 298.000 ? hors frais', 'Dit nieuwe project ligt op de versterkingen van de berg en biedt een buitengewoon uitzicht op de zee, op 5 minuten van het centrum van Aguilas, zijn winkels, bars en restaurants. De residentie biedt twee mooie grote zwembaden, een speeltuin voor kinderen, een ontspanningsruimte en ten slotte een gemeenschappelijke tuin. Alle appartementen hebben een parkeerplaats ondergronds met pre-installatie voor een elektrisch laadstation. De appartementen bestaan uit twee slaapkamers, twee badkamers en een grote woonkamer met open keuken, woonkamer en eetkamer. U zult ook genieten van prachtige grote terrassen. De keukens worden geleverd met oven, magnetron, kookplaat en afzuigkap. Airconditioning is ook bij de prijs inbegrepen. Prijs vanaf 298.000 euro exclusief kosten', '', 298000, 'aguilas-superbes-appartements-en-deux-chambres', 'aguilas-prachtige-appartementen-met-twee-kamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1567', 'Aspe: superbes appartements 2 chambres dans un très beau golf', 'Aspe: prachtige appartementen met 2 slaapkamers op een prachtige golfbaan', '', 'Ces appartements sont construits dans un nouveau golf, idéalement situé dans la province d''Alicante, à proximité d''Aspe et de Elche, à 20 minutes des belles plages de la Méditerranée et à seulement 15 minutes de l''aéroport d''Alicante. Sur le domaine, vous trouverez: - un parcours de golf de 18 trous - un club house - un magasin de golf - un restaurant typique espagnol - de nombreux chemins de balade et de VTT - des appartements, des maisons et des villas Les appartements jouissent de belles vues sur le golf et disposent de grandes baies vitrées, ce qui les rend très lumineux. Chaque appartement a également une place de parking. Certains appartements sont agencés en duplex. La résidence dispose d''une grande piscine commune avec de beaux jardins aménagés. Prix: Duplex: 425.000 ? hors frais Livraison: avril 2025', 'Deze appartementen zijn gebouwd op een nieuwe golfbaan, ideaal gelegen in de provincie Alicante, dicht bij Aspe en Elche, op 20 minuten van de prachtige stranden van de Middellandse Zee, en op slechts 10 minuten van de internationale luchthaven van Alicante. Op het golfdomein vindt u: - een 18-holes golfbaan - een clubhuis - een golfwinkel - een typisch Spaans restaurant - veel paden om te wandelen en mountainbiken - appartementen, huizen en villa''s De appartementen hebben een prachtig uitzicht op de golfbaan. Grote glaspartijen zorgen voor een maximale lichtinval. Elk appartement heeft ook een parkeerplaats. Sommige appartementen zijn op 2 levels (duplex). De residentie heeft een groot gemeenschappelijk zwembad met prachtig aangelegde tuinen. Prijs: Duplex: 425.000 ? exclusief kosten', '', 425000, 'aspe-superbes-appartements-2-chambres-dans-un-tres-beau-golf', 'aspe-prachtige-appartementen-met-2-slaapkamers-op-een-prachtige-golfbaan', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-0839', 'Appartements 1 chambre très modernes à Fuengirola - Mijas Costa', 'Zeer moderne appartementen met 1 slaapkamer in Fuengirola - Mijas Costa', 'Modern new 1 bedroom apartments, in Fuengirola-Mijas Costa', 'Cette nouvelle résidence comprend 124 appartements 1, 2 ou 3 chambres et des penthouses avec terrasses spacieuses offrant de belles vues sur les environs. Les appartements disposent de pièces lumineuses et spacieuses et sont conçus pour offrir un maximum de confort et des vues vues spectaculaires depuis les terrasses. Chaque appartement comprend un parking en sous-sol et une remise (inclus dans le prix). Les zones communes offrent une piscine, une salle de sport, des jardins et un parc de jeux pour les enfants. Cette résidence offre tous les avantages de séjourner dans le meilleur quartier commerçant de la Costa del Sol, à seulement 20 kms de l''aéroport. L''endroit idéal pour les amateurs de golf, de gastronomie, de shopping et de loisirs. Prix pour un appartement 1 chambre: à partir de 260.300 ? hors frais Fin des travaux: 4T2025', 'Dit nieuwe complex beschikt over 124 appartementen met 1, 2 of 3 slaapkamers en penthouses met ruime terrassen met een prachtig uitzicht op de omgeving. De appartementen hebben lichte, ruime kamers en zijn ontworpen om maximaal comfort en spectaculaire uitzichten vanaf de terrassen te bieden. Elk appartement heeft een ondergrondse parkeerplaats en een berging (in de prijs inbegrepen). De gemeenschappelijke ruimtes voorzien een zwembad, een fitnessruimte, tuinen en een speeltuin voor de kinderen. Deze residentie biedt alle voordelen van een verblijf in het beste winkelgebied van de Costa del Sol, op slechts 20 km van de luchthaven. De ideale plek voor liefhebbers van Golf, gastronomie, winkelen en vrije tijd. Prijzen voor een appartement met 1 slaapkamer: ? 260.300, exclusief kosten.', 'An innovative and elegant new promotion consisting of 124 apartments with 1, 2 and 3 bedrooms and penthouses with spacious terraces offering nice views of the surrounding area. The apartments have bright and spacious rooms, and are designed to offer maximum comfort and spectacular views from the spacious terraces. Every excellently finished apartment comes with a garage and storage room included in the sales price. The community areas offer a swimming pool, gym, gardens and children?s play park. All the advantages of living in the best shopping area on the Costa de Sol, and 20 kms from the airport. For lovers of golf, gastronomy,shopping and leisure, this is the right place for your new home on the Costa del Sol. Prices start from 154.700 ? excluding costs.', 260300, 'appartements-1-chambre-tres-modernes-a-fuengirola-mijas-costa', 'zeer-moderne-appartementen-met-1-slaapkamer-in-fuengirola-mijas-costa', 'modern-new-1-bedroom-apartments-in-fuengirola-mijas-costa', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-0840', 'A Fuengirola - Mijas Costa, beaux appartements 2 chambres modernes', 'Zeer moderne appartementen met 2 slaapkamers in Fuengirola - Mijas Costa', 'Modern new 2 bedroom apartments, in Fuengirola-Mijas Costa', 'Cette nouvelle résidence comprend 124 appartements 1, 2 ou 3 chambres et des penthouses avec terrasses spacieuses offrant de belles vues sur les environs. Les appartements disposent de pièces lumineuses et spacieuses et sont conçus pour offrir un maximum de confort et des vues vues spectaculaires depuis les terrasses. Chaque appartement comprend un parking en sous-sol et une remise (inclus dans le prix). Les zones communes offrent une piscine, une salle de sport, des jardins et un parc de jeux pour les enfants. Cette résidence offre tous les avantages de séjourner dans le meilleur quartier commerçant de la Costa del Sol, à seulement 20 kms de l''aéroport. L''endroit idéal pour les amateurs de golf, de gastronomie, de shopping et de loisirs. Prix pour un appartement 2 chambres: à partir de 329.900 ?, hors frais. Fin des travaux : 4T2025', 'Dit nieuwe complex beschikt over 124 appartementen met 1, 2 of 3 slaapkamers en penthouses met ruime terrassen met een prachtig uitzicht op de omgeving. De appartementen hebben lichte, ruime kamers en zijn ontworpen om maximaal comfort en spectaculaire uitzichten vanaf de terrassen te bieden. Elk appartement heeft een ondergrondse parkeerplaats en een berging (in de prijs inbegrepen). De gemeenschappelijke ruimtes voorzien een zwembad, een fitnessruimte, tuinen en een speeltuin voor de kinderen. Deze residentie biedt alle voordelen van een verblijf in het beste winkelgebied van de Costa del Sol, op slechts 20 km van de luchthaven. De ideale plek voor liefhebbers van Golf, gastronomie, winkelen en vrije tijd. Prijzen voor een appartement met 2 slaapkamers: vanaf ? 329.900 exclusief kosten.', 'An innovative and elegant new promotion consisting of 124 apartments with 1, 2 and 3 bedrooms and penthouses with spacious terraces offering nice views of the surrounding area. The apartments have bright and spacious rooms, and are designed to offer maximum comfort and spectacular views from the spacious terraces. Every excellently finished apartment comes with a garage and storage room included in the sales price. The community areas offer a swimming pool, gym, gardens and children?s play park. All the advantages of living in the best shopping area on the Costa de Sol, and 20 kms from the airport. For lovers of golf, gastronomy,shopping and leisure, this is the right place for your new home on the Costa del Sol. Prices start from 230.300 ? to 274.000 ? excluding costs.', 329900, 'a-fuengirola-mijas-costa-beaux-appartements-2-chambres-modernes', 'zeer-moderne-appartementen-met-2-slaapkamers-in-fuengirola-mijas-costa', 'modern-new-2-bedroom-apartments-in-fuengirola-mijas-costa', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-0841', 'Beaux appartements 3 chambres à Fuengirola - Mijas Costa', 'Zeer moderne appartementen met 3 slaapkamers in Fuengirola - Mijas Costa', 'Modern new 3 bedroom apartments, in Fuengirola-Mijas Costa', 'Cette nouvelle résidence comprend 124 appartements 1, 2 ou 3 chambres et des penthouses avec terrasses spacieuses offrant de belles vues sur les environs. Les appartements disposent de pièces lumineuses et spacieuses et sont conçus pour offrir un maximum de confort et des vues vues spectaculaires depuis les terrasses. Chaque appartement comprend un parking en sous-sol et une remise (inclus dans le prix). Les zones communes offrent une piscine, une salle de sport, des jardins et un parc de jeux pour les enfants. Cette résidence offre tous les avantages de séjourner dans le meilleur quartier commerçant de la Costa del Sol, à seulement 20 kms de l''aéroport. L''endroit idéal pour les amateurs de golf, de gastronomie, de shopping et de loisirs. Prix pour un appartement 3 chambres: à partir de 427.400 ?, hors frais. Fin des travaux : 4T2025', 'Dit nieuwe complex beschikt over 124 appartementen met 1, 2 of 3 slaapkamers en penthouses met ruime terrassen met een prachtig uitzicht op de omgeving. De appartementen hebben lichte, ruime kamers en zijn ontworpen om maximaal comfort en spectaculaire uitzichten vanaf de terrassen te bieden. Elk appartement heeft een ondergrondse parkeerplaats en een berging (in de prijs inbegrepen). De gemeenschappelijke ruimtes voorzien een zwembad, een fitnessruimte, tuinen en een speeltuin voor de kinderen. Deze residentie biedt alle voordelen van een verblijf in het beste winkelgebied van de Costa del Sol, op slechts 20 km van de luchthaven. De ideale plek voor liefhebbers van Golf, gastronomie, winkelen en vrije tijd. Prijzen voor een appartement met 3 slaapkamers: vanaf ? 427.400 exclusief kosten.', 'An innovative and elegant new promotion consisting of 124 apartments with 1, 2 and 3 bedrooms and penthouses with spacious terraces offering nice views of the surrounding area. The apartments have bright and spacious rooms, and are designed to offer maximum comfort and spectacular views from the spacious terraces. Every excellently finished apartment comes with a garage and storage room included in the sales price. The community areas offer a swimming pool, gym, gardens and children?s play park. All the advantages of living in the best shopping area on the Costa de Sol, and 20 kms from the airport. For lovers of golf, gastronomy,shopping and leisure, this is the right place for your new home on the Costa del Sol. Prices start from 260.400 ? to 295.700 ? excluding costs.', 427400, 'beaux-appartements-3-chambres-a-fuengirola-mijas-costa', 'zeer-moderne-appartementen-met-3-slaapkamers-in-fuengirola-mijas-costa', 'modern-new-3-bedroom-apartments-in-fuengirola-mijas-costa', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-0861', 'DERNIERE UNITE! En front de mer à Estepona, superbes appartements 3 chambres', 'LAST UNIT! Aan de kustlijn van Estepona, prachtige appartementen met 3 slaapkamers', 'New frontline beach exclusive 3 bedroom luxury apartments, in Estepona', 'Résidence exclusive située à Estepona, jouissant de belles vues sur mer et située dans un cadre pittoresque. Les appartements ont 1 à 4 chambres et bénéficient de finitions de haute qualité. Quelques caractéristiques sont: hauteur des plafonds, carrelages en porcelaine grand format, utilisation du bois dans les chambres... Chaque appartement dispose d''une belle terrasse privée, d''un emplacement de parking privé ainsi que d''une remise. La résidence compte une piscine à débordement et un espace fitness. Pas moins de 10 terrains de golf sont situés à moins de 20 minutes en voiture de la résidence. L''aéroport de Malaga se trouve à environ 75 km (50 minutes). Prix: 1.875.000 ? au 6ème étage', 'Deze exclusieve residentie in gelegen in Estepona. U kan er genieten van het zicht op de prachtige stranden in een pitoresk kader. De appartementen hebben 1 tot 4 slaapkamers en genieten van een hoge kwalitatieve afwerking. Hoge plafond, grote porceleinen tegels en houten afwerking in de slaapkamers zijn hier enkele voorbeelden van. Elk appartement beschikt over een privé terras en een gereserveerd parkeerplaats met berging. Op het domein staat een gemeenschappelijk zwembad en een fitnessruimte. Er zijn maar liefst 10 golfterreinen op minder dan 20 minuten rijden. De luchthaven van Malaga is op 75km. Prijs: 1.875.000 ? zonder kosten.', 'An exclusive development located in Estepona, with beautiful sea views and picturesque surroundings. This great development consists of an assortment of seafront apartments ranging in size from 1 to 4 bedrooms. Each apartment comes with its own terrace, and with high quality finishes and touches, such as the height of the ceilings, floor-to-ceiling doors, large-format porcelain floor tiles and the use of wood in bedrooms. The properties benefit from access to the complex?s infinity pool and gym. Each apartment comes along with its own parking space as well as its own storage space. There are 10 golf courses located less than a 20 mins drive from the apartments. The property lies around 75km (50mins) from Malaga airport. Prices start at 890.000 ? + costs.', 1875000, 'derniere-unite-en-front-de-mer-a-estepona-superbes-appartements-3-chambres', 'last-unit-aan-de-kustlijn-van-estepona-prachtige-appartementen-met-3-slaapkamers', 'new-frontline-beach-exclusive-3-bedroom-luxury-apartments-in-estepona', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-0983', 'Somptueuse villa 5 chambres à Cabo de Palos, avec vue imprenable sur la mer', 'Luxueuze villa met 5 slaapkamers in Cabo de Palos, met een adembenemend zicht op zee', '', 'Somptueuse villa située à Cala Medina, un paradis pour la vue, où vous pourrez profiter du littoral, de l''immensité de la mer Méditerranée, et de superbes couchers de soleil. L''endroit, en plus d''être un paradis pour les amoureux de plongée, regorge de criques paradisiaques pour se baigner et pour pratiquer des sports nautiques. Situation idéale: à 5 minutes du port de plaisance de Cabo de Palos, de sa promenade et de ses restaurants où vous pourrez déguster de merveilleux plats méditerranéens. A 3 minutes de l''autoroute et à seulement 2 km du prestigieux La Manga Club Resort. Parcelle de 1000 mètres carrés, 585 mètres carrés construits avec des vues incroyables sur la mer Méditerranée, sur les falaises spectaculaires et sur le phare de Cabo de Palos. La villa comprend un jardin entièrement fini de 805 m², avec piscine privée, ascenseur, garage, SPA avec jacuzzi, sauna et douches (en option), barbecue (en option), air conditionné, chauffage par le sol, 5 chambres, 3 salles de bain entièrement équipées, 2 toilettes, cuisine design personnalisable, entièrement meublée, salon, salle à manger, buanderie, salle de stockage, garage pour deux voitures et un parking pour une voiture supplémentaire, plusieurs terrasses, solarium et véranda.', 'Luxueuze villa gelegen in Cala Medina, een streling voor het oog omwille van het zicht op de Middellandse zee en de prachtige zonsondergang. Het is een paradijs voor duikers, zwemmers en zij die houden van alle andere watersporten. Ideale ligging: op 5 minuten van de jachthaven van Cabo de Palos, van de promenade en van vele restaurants waar u gastronomisch wordt verwend. Op 3 minuten verwijderd ligt de autosnelweg en op 2km ligt het prestigieuze La Manga Club Resort. Het perceel is 1000m2 groot waarvan 585m2 bebouwd en biedt een prachtig zicht op de Middellandse Zee, de spectaculaire kliffen en de vuurtoren van Cabo de Palos. De villa heeft een volledig afgewerkte tuin van 805m2, een privé zwembad, lift, SPA met jacuzzi, sauna en douches (optioneel), barbecue (optioneel), airco, vloerverwarming, 5 slaapkamers, 3 volledige uitgeruste badkamers, 2 toiletten, keuken nog te personaliseren en volledig bemeubeld, salon, eetkamer, wasruimte, berging, garage voor twee auto?s en een extra parkeerplaats voor een auto, meerdere terrassen, een solarium en een veranda.', '', 3950000, 'somptueuse-villa-5-chambres-a-cabo-de-palos-avec-vue-imprenable-sur-la-mer', 'luxueuze-villa-met-5-slaapkamers-in-cabo-de-palos-met-een-adembenemend-zicht-op-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1741', 'Orihuela Costa: superbes appartements 2 chambres situés au calme près d''un golf', '', '', 'Ces beaux appartements 2 chambres sont situés au calme, à proximité d''un terrain de golf. Les belles plages de Guardamar et d''Orihuela Costa sont situées à 15 minutes en voiture et l''aéroport d''Alicante à 35 minutes. Dans le resort, vous trouverez une multitude de restaurants, bars, un supermarché et un terrain de paddle tennis. C''est l''endroit idéal pour passer d''agréables vacances au calme et pour profiter du soleil toute l''année! Cette résidence privée dispose également de beaux jardins autour d''une grande piscine commune. Les appartements disposent de 2 chambres et de 2 salles de bains et d''une cuisine ouverte donnant sur le vaste living avec baies vitrées vers la terrasse. Ils sont situés soit au rez-de-chaussée avec jardin, soit au 1er étage avec solarium. Prix: Rez: àpd 239.900 ? hors frais Solarium: àpd 269.900 ? hors frais Fin des travaux: décembre 2026', '', '', 239900, 'orihuela-costa-superbes-appartements-2-chambres-situes-au-calme-pres-d-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1040', 'DERNIERE UNITE! Fantastiques appartements 3 chambres en 1ère ligne de mer à Torremolinos', 'LAST UNIT! Fantastische appartementen met 3 slaapkamers, eerste lijn aan zee te Torremolinos', 'Very high standart new appartments on the front line sea at Torremolinos', 'Résidence avant-gardiste et innovante, conçue pour tirer le meilleur parti des fabuleuses vues sur la Méditerranée. La résidence compte des appartements 1, 2 ou 3 chambres et est idéalement située à Torremolinos, dans l''une des zones les plus prisées de la Costa del Sol, à 6,5 km du Golf Parador de Malaga, à 8 km de l''aéroport international et à 10 km du centre ville de Malaga. Le complexe dispose en outre d''une piscine extérieure, d''une piscine intérieure chauffée, d''un parcours de running, d''un espace bien-être avec sauna, bain turc et salle de gym équipée. Sécurité 24h/24. Prix: Appartements 3 chambres: 1.950.000 ? hors frais (au 4ème étage) Inclus dans le prix: cuisine équipée, place de parking, remise, sols radiants et système d''aérothermie.', 'Nieuwe residentie avant-garde en innovatief, zodanig ontworpen om van de beste zichten op de Middelandse zee te genieten. De residentie heeft appartementen met 1, 2 of 3 slaapkamers en ligt perfect gelegen in Torremolinos, een populaire buurt in de Costa del Sol, op 6,5km van de Golf Parador van Malaga en op 8km van de luchthaven van Malaga. Het centrum van Malaga ligt op 10km. Het complex beschikt over een buitenzwembad, een verwarmd binnenzwembad, een loopparcours, een welnessruimte met spa en turks stoombad en een fitnessruimte. Beveiliging 24u/24u. Prijs: Appartementen met 3 slaapkamers: 1.950.000? exclusief kosten. Inbegrepen in de prijs: volledig uitgeruste keuken, parkeerplaats, aerothermisch systeem,..', 'This is a residential complex of avant-garde and innovative design, designed to make the most of the fabulous open views of the Mediterranean Sea. Merged with the sea, its architecture is perfectly linked with it. Offering unique sights where connecting with the core essence of nature is easier than ever before. Strategically located, this complex of 1, 2 or 3 bedrooms lays on one of the most merging areas on the Costa del Sol. Going along with unbeatable connection with main transport and and with the International Airport and the city?s port. It counts with excellent communication with commercial, leisure and dining areas. Located just at 800 meters from the Parador Málaga Golf, 6.5km from International Malaga Airport and just 10 minutes far from Malaga city centre. Parking space and storage are included in the price among all these features/ facilities: Outdoor pool Olympic length pool Indoor heated pool Running circuit inside the residential 24/7 security Equipped kitchen of Gunni and Trentino Sauna, Turkish bath and fully equipped gym Multipurpose room Glazed facade Radiant floors throughout the house, aerothermia and suspended toilets... Prices start at 592.000 euros plus costs.', 1950000, 'derniere-unite-fantastiques-appartements-3-chambres-en-1ere-ligne-de-mer-a-torremolinos', 'last-unit-fantastische-appartementen-met-3-slaapkamers-eerste-lijn-aan-zee-te-torremolinos', 'very-high-standart-new-appartments-on-the-front-line-sea-at-torremolinos', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1082', 'DERNIERE UNITE ! Appartements modernes avec 2 chambres sur le golf de La Finca', 'LAST UNIT ! Moderne 2 slaapkamer appartementen aan de golf van La Finca.', '', 'Superbes appartements situés sur le golf de La Finca, à proximité de Algorfa, et à 10 minutes des belles plages de Guardamar. Situation idéale, au calme, facilement accessible via les aéroports internationaux d''Alicante et de Murcie. Les appartements 2 chambres et 2 salles de bains situés au rez-de-chaussée disposent d''une terrasse de 15 à 20 m² ainsi que d''un vaste jardin (de 95 m² à 142 m²). Les appartements situés au 1er étage disposent d''une terrasse de 13 à 22 m² ainsi que d''un beau solarium (de 31 à 61 m²). La résidence compte une belle piscine commune entourée de jardins. Vous jouirez d''une grande tranquillité, tout en étant proche de nombreuses facilités. Excellente qualité de construction! Prix: Rez-de-chaussée: 249.000 ? hors frais Inclus: - Système domotique - Volets électriques - Système d''alarme - Jardin aménagé avec irrigation - Luminaires extérieurs', 'Fantastische appartementen gelegen aan de golf van La Finca, in de buurt van Algorfa, en op 10 minuten van de prachtige stranden van Guardamar. Deze rustige locatie is ideaal gelegen doordat ze gemakkelijk bereikbaar is via de internationale luchthavens van Alicante en Murcia. Appartementen met 2 slaapkamers en 2 badkamers met tuin of met solarium. Prijs: ?249.000, excl kosten. Dit project is van uitstekende kwaliteit! Kom het nu ontdekken!', '', 249000, 'derniere-unite-appartements-modernes-avec-2-chambres-sur-le-golf-de-la-finca', 'last-unit-moderne-2-slaapkamer-appartementen-aan-de-golf-van-la-finca', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1083', 'A Playa Flamenca, appartements 2 chambres dans une superbe résidence', 'Playa Flamenca, appartementen met twee kamers in een prachtig complex', '', 'Cette toute nouvelle résidence est construite comme un vrai village au coeur de Playa Flamenca et vous offre de grands parcs, des sentiers pédestres et des pistes cyclables. Elle compte en outre des façades avec des bacs à fleurs, de grandes jardinières, des portiques en pierre, un lac, des fontaines, une belle grande piscine avec espace de détente, des jacuzzis, un espace aquatique avec jeux pour enfants, une salle de sport avec vue sur le lac et un sauna finlandais. Il s''agit d''un projet éco-responsable qui recherche l''efficacité, d''un point de vue économique et environnemental. L''éclairage à LED, les robinets éco-efficaces, les nappes d''eau dans les espaces verts sont quelques-unes des caractéristiques intégrées à ce projet. Le tout idéalement situé à Playa Flamenca: non loin des plages, des terrains de golf et de nombreux commerces. Le centre commercial La Zenia Boulevard se trouve à distance de marche de là. Les appartements 2 chambres comptent 1 ou 2 salles de bains, une buanderie, une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse. Prix: A partir de 340.000 ? hors frais', 'Deze gloednieuwe residentie is gebouwd als een echt dorp in het hart van Playa Flamenca en biedt u grote parken, wandelpaden en fietspaden. Het heeft ook gevels met bloemperken, grote plantenbakken, stenen portieken, een meer, fonteinen, een prachtig groot zwembad met ontspanningsruimte, jacuzzi''s, een waterpark met spelletjes voor kinderen, een speelkamer voor kinderen. sport met uitzicht op het meer en Finse sauna. Het is een milieuvriendelijk project dat vanuit economisch en ecologisch oogpunt efficiëntie nastreeft. LED-verlichting, eco-efficiënte kranen, watertafels in groene ruimtes zijn enkele van de kenmerken van dit project. Allemaal ideaal gelegen in Playa Flamenca: niet ver van stranden, golfbanen en veel winkels. Winkelcentrum La Zenia Boulevard ligt op loopafstand. De appartementen met 2 slaapkamers hebben 1 of 2 badkamers, een wasruimte, een open keuken die leidt naar de woonkamer met openslaande deuren naar het terras. Prijs vanaf 340.000 euro exclusief kosten', '', 340000, 'a-playa-flamenca-appartements-2-chambres-dans-une-superbe-residence', 'playa-flamenca-appartementen-met-twee-kamers-in-een-prachtig-complex', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1084', 'Superbes appartements 3 chambres très bien situés à Playa Flamenca', 'Schitterende appartementen 3 kamers heel goed gelegen in Playa Flamenca', '', 'Cette toute nouvelle résidence est construite comme un vrai village au coeur de Playa Flamenca et vous offre de grands parcs, des sentiers pédestres et des pistes cyclables. Elle compte en outre des façades avec des bacs à fleurs, de grandes jardinières, des portiques en pierre, un lac, des fontaines, une belle grande piscine avec espace de détente, des jacuzzis, un espace aquatique avec jeux pour enfants, une salle de sport avec vue sur le lac et un sauna finlandais. Il s''agit d''un projet éco-responsable qui recherche l''efficacité, d''un point de vue économique et environnemental. L''éclairage à LED, les robinets éco-efficaces, les nappes d''eau dans les espaces verts sont quelques-unes des caractéristiques intégrées à ce projet. Le tout idéalement situé à Playa Flamenca: non loin des plages, des terrains de golf et de nombreux commerces. Le centre commercial La Zenia Boulevard se trouve à distance de marche de là. Les appartements 3 chambres comptent 2 salles de bains, une buanderie, une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse. Prix: A partir de 462.000 ? hors frais', 'Deze gloednieuwe residentie is gebouwd als een echt dorp in het hart van Playa Flamenca en biedt u grote parken, wandelpaden en fietspaden. Het heeft ook gevels met bloemperken, grote plantenbakken, stenen portieken, een meer, fonteinen, een prachtig groot zwembad met ontspanningsruimte, jacuzzi''s, een waterpark met spelletjes voor kinderen, een speelkamer voor kinderen. sport met uitzicht op het meer en Finse sauna. Het is een milieuvriendelijk project dat vanuit economisch en ecologisch oogpunt efficiëntie nastreeft. LED-verlichting, eco-efficiënte kranen, watertafels in groene ruimtes zijn enkele van de kenmerken van dit project. Allemaal ideaal gelegen in Playa Flamenca: niet ver van stranden, golfbanen en veel winkels. Winkelcentrum La Zenia Boulevard ligt op loopafstand. De appartementen met 3 slaapkamers hebben 2 badkamers, een bijkeuken, een open keuken die leidt naar de woonkamer met openslaande deuren naar het terras. Prijs vanaf 462.000 euro exclusief kosten', '', 462000, 'superbes-appartements-3-chambres-tres-bien-situes-a-playa-flamenca', 'schitterende-appartementen-3-kamers-heel-goed-gelegen-in-playa-flamenca', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1632', 'Orihuela Costa: superbes appartements très bien situés en deux chambres', '', '', 'Ces superbes appartements se situent à distance de marche de la plage et du fameux centre commercial La Zenia Boulevard. A proximité, vous trouverez aussi des supermarchés, pharmacies, boulangeries, bars et restaurants. La résidence compte des appartements en deux ou trois chambres. Une belle piscine et des jardins communs sont à disposition des propriétaires. Ces spacieux appartements sont baignés de lumière naturelle grâce à de grandes baies vitrées. Chaque appartement jouit de belles terrasses et d''une place de parking inclus dans le prix. Prix à partir de 329.800 ? hors frais Pas de penthouse disponible en deux chambres', '', '', 329800, 'orihuela-costa-superbes-appartements-tres-bien-situes-en-deux-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1621', 'Los Montesinos: Villas contemporaines en trois chambres', '', '', 'Los Montesinos est un village proche de Torrevieja et de Guardamar, situé en bordure d''un grand parc naturel. L''endroit est idéal pour ceux qui désirent vivre dans le calme mais pouvoir en quelques instants retrouver la vie animée des stations balnéaires. Toutes les commodités se trouvent dans le village. Les villas sont de type contemporaines et disposent d''une piscine privée et d'' un emplacement de parking sur la parcelle. Elles jouissent en outre d''une grande terrasse au rez-de-chaussée, d''une autre au premier étage et enfin, d''un grand solarium avec une vue à 360°. Les deux salles de bains possèdent un chauffage sol et la villa est dotée de volets électriques. Les trois chambres sont équipées de placards intégrés. Prix à partir de 405.900 ? hors frais Dans le prix sont inclus les électroménagers..', '', '', 405900, 'los-montesinos-villas-contemporaines-en-trois-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1655', 'Villas au c?ur d''un golf en 3 chambres', '', '', 'Ce nouveau développement se trouve à 15 minutes du centre historique de Murcia, à 15 minutes de l''aéroport de Corvera (Murcia) et à 20 minutes des plages. Ce resort, outre son parcours de golf, dispose aussi de terrains de tennis et de paddle. Les chemins de randonnées et les pistes de VTT pullulent dans cette région toute proche du superbe parc naturel de la Sierra de Carrascoy. Les parcelles vont de 300m² à 793m². Les villas sont proposées en 3 chambres (de plain-pied) avec un jardin privatif et une piscine privée. Certaines maisons disposent d''un garage fermé. Il existe 5 versions différentes possibles pour ces villas, vous n''aurez que l''embarras du choix. Vous pourrez profitez en toute quiétude des charmes de la vie méditerranéenne sur le mode farniente ou sportif ou culturel. Prix à partir de 375.900? hors frais', '', '', 375900, 'villas-au-c-ur-d-un-golf-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1742', 'Orihuela Costa: superbes appartements 3 chambres situés au calme près d''un golf', '', '', 'Ces beaux appartements 3 chambres sont situés au calme, à proximité d''un terrain de golf. Les belles plages de Guardamar et d''Orihuela Costa sont situées à 15 minutes en voiture et l''aéroport d''Alicante à 35 minutes. Dans le resort, vous trouverez une multitude de restaurants, bars, un supermarché et un terrain de paddle tennis. C''est l''endroit idéal pour passer d''agréables vacances au calme et pour profiter du soleil toute l''année! Cette résidence privée dispose également de beaux jardins autour d''une grande piscine commune. Les appartements disposent de 3 chambres et de 2 salles de bains et d''une cuisine ouverte donnant sur le vaste living avec baies vitrées vers la terrasse. Ils sont situés soit au rez-de-chaussée avec jardin, soit au 1er étage avec solarium. Prix: à partir de 279.900 ? hors frais', '', '', 299900, 'orihuela-costa-superbes-appartements-3-chambres-situes-au-calme-pres-d-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1146', 'Daya Nueva: très jolies villas en trois chambres', 'Daya Nueva: zeer mooie villa''s met drie kamers', '', 'Ce projet de villas adossées et de plain pied se situe à Daya Nueva, charmante localité à 15 minutes des magnifiques plages de Guardamar. A proximité, vous trouverez toutes les commodités: restaurants, bars et commerces. Ces habitations sont composées de trois chambres, deux salles de bains,une buanderie, un large living, salle à manger et une belle cuisine ouverte avec un îlot central. Dans la suite parentale, vous trouverez un dressing. L''extérieur se compose d''un grande terrasse, d''une piscine incluse dans le prix et d''un emplacement pour la voiture, le tout complètement fermé. Prix: à partir de 365.000 euros hors frais', 'Dit project van gelijkvloerse villa''s bevindt zich in Daya Vieja, een charmant stadje op 15 minuten van de prachtige stranden van Guardamar. In de omgeving vindt u alle voorzieningen: restaurants, bars en winkels. Deze woningen bestaan uit drie slaapkamers, twee badkamers, een wasruimte, een grote woonkamer, een eetkamer en een mooie open keuken met een centraal eiland. De master slaapkamer heeft ook een dressing. Buiten beschikt men over een groot terras, een zwembad en een parkeerplaats. Het is eveneens volledig omheind. Prijs: vanaf ?365.000 exclusief kosten.', '', 365000, 'daya-nueva-tres-jolies-villas-en-trois-chambres', 'daya-nueva-zeer-mooie-villa-s-met-drie-kamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1169', 'Los Montesinos: sublimes villas 3 chambres', 'Los Montesinos: sublieme villa''s met 3 slaapkamers', '', 'Situées dans la région de Los Montesinos, ces nouvelles villas offrent tout le luxe et la tranquillité possible avec 3 chambres et 2 ou 3 salles de bains, une belle cuisine équipée, une vaste pièce de vie très lumineuse sur des parcelles allant de 341 m² à 367 m². Le village et tous les types de commerces et de service se trouvent à distance de marche. Prix: àpd 509.000 ? hors frais Inclus dans le prix: -électroménagers -Spots encastrés dans le salon, la cuisine, le living et les salles de bains. Spots extérieurs sur la façade. -Piscine (4m x 8m) -chauffage au sol dans les salles de bains -climatisation Possibilité d''ajouter une 4ème chambre moyennant supplément', 'Deze nieuwe villa''s liggen in de buurt van Los Montesinos en bieden alle luxe en rust die mogelijk is! Ze bestaan uit 3 slaapkamers en 2 of 3 badkamers, een mooie ingerichte keuken en een grote lichte woonkamer. Dit alles op kavels van 341 m² tot 367 m² . Het dorp, verschillende winkels en de nodige diensten liggen allemaal op loopafstand. Prijs: vanaf ?509.000 exclusief kosten. Inbegrepen in de prijs: -elektrische apparaten in de keuken -Inbouwspots in de woonkamer, keuken, woonkamer en badkamers. Buitenspots op de gevel. -Zwembad (4m x 8m) -vloerverwarming in de badkamers -airco Mogelijkheid om een ??4de slaapkamer toe te voegen (tegen toeslag)', '', 509000, 'los-montesinos-sublimes-villas-3-chambres', 'los-montesinos-sublieme-villa-s-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1692', 'Pilar de la Horadada: appartements 2 chambres dans une nouvelle résidence', '', '', 'Cette nouvelle résidence est idéalement située à Pilar de la Horadada, à 3 km des belles plages de Higuericas et à 5 minutes à pied du centre de Pilar avec ses nombreux commerces, supermarchés et restaurants. La résidence comptera 28 appartements 2 chambres, situés soit au rez-de-chaussée (avec patio à l''arrière et terrasse et jardin à l''avant), soit au 1er étage (avec terrasse et vaste solarium). Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte donnant sur le salon avec baies vitrées vers la terrasse et d''une buanderie. Tous les appartements donnent sur la belle piscine commune. Prix: A partir de 225.000 ? hors frais Fin des travaux : février ou avril 2027', '', '', 225000, 'pilar-de-la-horadada-appartements-2-chambres-dans-une-nouvelle-residence', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1239', 'Daya Nueva: magnifiques villas semi-détachées trois chambres', 'Daya Nueva : prachtige villa''s met drie slaapkamers, halfopen bebouwing', '', 'Ce projet se situe à Daya Nueva à 10 minutes des plages de Guardamar. Plusieurs golfs sont à courte distance de là et les commerces sont dans les proches alentours. Les villas se composent au rez-de-chaussée de la suite parentale avec salle de bains en suite, d''un vaste espace de vie regroupant une cuisine ouverte avec îlot central, une salle à manger et un lumineux salon donnant sur la terrasse et la piscine privée. Au premier étage, se trouvent les deux chambres invités et la deuxième salle de bains ainsi qu''un beau solarium. Sur la parcelle est prévue une place de parking et la piscine est comprise dans le prix Prix à partir de 311.000 euros hors frais', 'Dit project is gelegen in Daya Nueva, op 10 minuten van de stranden van Guardamar. Verschillende golfbanen liggen op korte afstand en er zijn winkels in de buurt. Op het gelijkvloers heb je in de villa''s de master suite met bijbehorende badkamer, een grote leefruimte met een open keuken met kookeiland, een eetkamer en een goed verlichte woonkamer met uitzicht op het terras en het privé zwembad. Op de eerste verdieping zijn de twee gastenslaapkamers, de tweede badkamer en een prachtig dakterras. Het perceel is voorzien van een parkeerplaats en het zwembad is inbegrepen in de prijs Prijs vanaf ? 299.000 exclusief kosten', '', 311000, 'daya-nueva-magnifiques-villas-semi-detachees-trois-chambres', 'daya-nueva-prachtige-villa-s-met-drie-slaapkamers-halfopen-bebouwing', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1251', 'Cumbre del Sol: superbes appartements 2 chambres très modernes', 'Cumbre del Sol: prachtige en moderne appartementen met twee slaapkamers', '', 'Ces beaux appartements 2 chambres sont situés à Cumbre del Sol (Benitachell), à quelques kilomètres de Moraira et de Javéa. Le cadre exceptionnel de la résidence vous permet de profiter de la nature et d''une vue magnifique sur la mer. A portée de main, vous avez accès à tous les services dont vous avez besoin au quotidien: supermarché, restaurants, bars, pharmacie, salon de beauté,... Les appartements disposent de 2 chambres, de 2 salles de bains, d''une cuisine ouverte sur le salon avec portes-fenêtres vers la terrasse et d''une buanderie. Les appartements du rez-de-chaussée disposent d''un jardin, ceux du dernier étage d''un solarium. Espaces communs avec belle piscine, jardins, aire de jeux pour enfants et club social. Prix: à partir de 454.000 ? hors frais Inclus: climatisation, chauffage par le sol et électroménagers.', 'Deze prachtige appartementen zijn gelegen in Cumbre del Sol (Benitachell), op enkele kilometers van Moraira en Javea. De uitzonderlijke ligging van de residentie laat u genieten van de natuur en van een prachtig uitzicht op zee. U hebt toegang tot alle dagdagelijkse faciliteiten: een supermarkt, restaurants, bars, apotheek, schoonheidssalon ,. .. De appartementen beschikken over 2 slaapkamers, 2 badkamers, een open keuken die uigeeft op de woonkamer met schuiframen naar het terras en een wasruimte. De appartementen op het gelijkvloers hebben een eigen tuin, die op de bovenste verdieping een dakterras. Gemeenschappelijke ruimtes met een prachtig zwembad, tuinen, een kinderspeeltuin en een sociale club. Prijs: vanaf ? 454.000 exclusief kosten Inclusief: airconditioning, vloerverwarming en keukentoestellen.', '', 454000, 'cumbre-del-sol-superbes-appartements-2-chambres-tres-modernes', 'cumbre-del-sol-prachtige-en-moderne-appartementen-met-twee-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1253', 'DERNIERE UNITE ! Santiago de la Ribeira: belles villas en trois chambres', 'Santiago de la Ribeira: mooie villa''s met drie slaapkamers', '', 'Ces belles villas 3 chambres sont situées à seulement 750 m des plages et à distance de marche de nombreux commerces, cafés et restaurants. La belle ville de Murcie se trouve à 30 minutes en voiture. Les 10 villas se composent au rez-de-chaussée d''un chambre, d''une salle de bains, d''une belle cuisine ouverte avec un îlot central, d''un vaste living et d''un WC séparé. Garage fermé. Belle terrasse avec piscine privée. Au premier étage, se trouvent deux chambres, chacune avec dressing et salle de bains, ainsi qu''une spacieuse terrasse de 28 m². Au 2ème étage: solarium de 50 m². Sont inclus dans le prix: - climatisation - électroménagers - garage - cuisine d''été - pergola sur le solarium - volets électriques (sauf dans les salles de bains) - pelouse artificielle - chauffage au sol dans les 3 salles de bains - pré-installation pour voiture électrique Prix: 549.000 ? hors frais', '', '', 549000, 'derniere-unite-santiago-de-la-ribeira-belles-villas-en-trois-chambres', 'santiago-de-la-ribeira-mooie-villa-s-met-drie-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1842', 'Santiago de la Ribera: belles villas 3 chambres proches de la mer', '', '', 'Ces belles villas sont situées à seulement 800 mètres de la plage de Santiago de la Ribera. Cette belle ville a un caractère moderne, mais en même temps c''est un endroit idéal pour goûter à la vraie vie espagnole. La région est également idéale pour les amateurs de sports de plein air, avec plusieurs terrains de golf à proximité, des sentiers de randonnée dans les montagnes environnantes et des sports nautiques sur les plages de la Mar Menor. L''autoroute AP7 permet de rejoindre rapidement et facilement d''autres grandes villes de la région, comme Murcie et Carthagène en 30 minutes, et Alicante en une heure. La promotion propose des villas jumelées modernes avec un terrain de 300 m2 et composées de 3 chambres et 2 salles de bains, réparties sur un seul étage, avec de grands porches, jardin et piscine privée. La zone principale dispose d''un espace de jour ouvert, composé d''un salon-salle à manger et d''une cuisine avec de grandes fenêtres donnant accès à l''espace extérieur. Vous trouverez également une chambre parentale avec sa salle de bains privée, deux chambres avec accès direct au jardin, une salle de bains et une buanderie. Prix: de 439.900 ? à 449.900 ? hors frais', '', '', 439900, 'santiago-de-la-ribera-belles-villas-3-chambres-proches-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
